import boto3
import json

def process_message(message):
    # Implement your logic to process different message types
    try:
        message_body = json.loads(message['Body'])
        message_type = message_body.get('type')

        if message_type == 'email':
            send_email(message_body)
        elif message_type == 'notification':
            send_notification(message_body)
        else:
            print(f"Unknown message type: {message_type}")
    except Exception as e:
        print(f"Error processing message: {e}")

def send_email(data):
    # Implement email sending logic
    print("Sending email:", data)

def send_notification(data):
    # Implement notification sending logic
    print("Sending notification:", data)

def worker():
    sqs = boto3.client('sqs', region_name='your-region')
    queue_url = 'your-queue-url'

    while True:
        response = sqs.receive_message(
            QueueUrl=queue_url,
            MaxNumberOfMessages=10,
            WaitTimeSeconds=20
        )

        messages = response.get('Messages', [])
        for message in messages:
            process_message(message)
            sqs.delete_message(QueueUrl=queue_url, ReceiptHandle=message['ReceiptHandle'])

if __name__ == '__main__':
    worker()